upstreamBackupRegionMarketsHydrate.query:
query BackupRegionMarketsHydrate($first: Int!, $regionsFirst: Int!) {
  markets(first: $first) {
    nodes {
      id
      name
      handle
      status
      type
      conditions {
        conditionTypes
        regionsCondition {
          regions(first: $regionsFirst) {
            nodes {
              __typename
              id
              name
              ... on MarketRegionCountry {
                code
              }
            }
          }
        }
      }
    }
  }
}

